// ============================================================
// WF5 - YouTube Outlier Research
// Full pipeline: YouTube → Transcript → Claude → Airtable
// ============================================================

const config = $input.first().json;
const YOUTUBE_KEY = config.YOUTUBE_API_KEY;
const SUPADATA_KEY = config.SUPADATA_API_KEY;
const ANTHROPIC_KEY = config.ANTHROPIC_API_KEY;
const AIRTABLE_TOKEN = config.AIRTABLE_TOKEN;
const AIRTABLE_BASE_ID = config.AIRTABLE_BASE_ID;
const OUTLIER_THRESHOLD = Number(config.OUTLIER_THRESHOLD) || 3;

const AIRTABLE_BASE = `https://api.airtable.com/v0/${AIRTABLE_BASE_ID}`;
const AT_HEADERS = {
  'Authorization': `Bearer ${AIRTABLE_TOKEN}`,
  'Content-Type': 'application/json'
};

// ---- Brand voice prompt for Claude ----
const BRAND_VOICE_PROMPT = `You are writing a YouTube video script for Mbusiness Branding AI.

Brand voice rules:
- Tone: Confident, honest, direct, no fluff, straight to the point
- Signature: Use "Perfect!" naturally at key moments — shows solution-oriented energy
- Never say "I can't" — always action-focused and positive
- Audience: Small home services business owners (plumbers, electricians, roofers, HVAC, landscapers) who are too busy to figure out AI tools themselves

Task: Rewrite the transcript below as an original video script in my brand voice. Keep the proven hook structure and core topic. Change examples to fit the home services world. Where relevant, weave in what Mbusiness Branding AI offers: AI-powered websites for lead capture, 24/7 AI receptionist for inquiries and booking, Google review management, and social media creation.

Format your response as:
[HOOK] (first 15 seconds — stop-the-scroll opening line)

[BODY] (main content — teach the concept in a relatable way for home service owners)

[CTA] (call to action — tie back to Mbusiness Branding AI and what to do next)

TRANSCRIPT TO REWRITE:
`;

const results = [];

// ---- STEP 1: Get active channels from Airtable ----
let channels = [];
try {
  const channelsRes = await fetch(
    `${AIRTABLE_BASE}/Channels?filterByFormula=${encodeURIComponent('{Active}=1')}`,
    { headers: AT_HEADERS }
  );
  const channelsData = await channelsRes.json();
  channels = channelsData.records || [];
} catch (e) {
  return [{ json: { status: 'error', step: 'get_channels', error: e.message } }];
}

if (channels.length === 0) {
  return [{ json: { status: 'done', message: 'No active channels. Add channels to the Airtable Channels table and check the Active box.', outliers_saved: 0 } }];
}

// ---- STEP 2: Process each channel ----
for (const channel of channels) {
  const channelId = channel.fields['Channel ID'];
  const channelName = channel.fields['Channel Name'];
  const channelRecordId = channel.id;

  if (!channelId) continue;

  try {
    // Get uploads playlist ID
    const chRes = await fetch(
      `https://www.googleapis.com/youtube/v3/channels?part=contentDetails&id=${channelId}&key=${YOUTUBE_KEY}`
    );
    const chData = await chRes.json();

    if (chData.error) {
      results.push({ channelName, status: 'error', error: `YouTube API: ${chData.error.message}` });
      continue;
    }

    const uploadsPlaylistId = chData.items?.[0]?.contentDetails?.relatedPlaylists?.uploads;
    if (!uploadsPlaylistId) {
      results.push({ channelName, status: 'skip', reason: 'No uploads playlist found' });
      continue;
    }

    // Get last 20 videos
    const plRes = await fetch(
      `https://www.googleapis.com/youtube/v3/playlistItems?part=contentDetails,snippet&playlistId=${uploadsPlaylistId}&maxResults=20&key=${YOUTUBE_KEY}`
    );
    const plData = await plRes.json();
    const playlistItems = plData.items || [];

    if (playlistItems.length < 3) {
      results.push({ channelName, status: 'skip', reason: 'Not enough videos to calculate average' });
      continue;
    }

    const videoIds = playlistItems.map(v => v.contentDetails.videoId);
    const videoMeta = {};
    playlistItems.forEach(v => {
      videoMeta[v.contentDetails.videoId] = {
        title: v.snippet.title,
        thumbnail: v.snippet.thumbnails?.high?.url || v.snippet.thumbnails?.default?.url || ''
      };
    });

    // Get video statistics (batch call)
    const statsRes = await fetch(
      `https://www.googleapis.com/youtube/v3/videos?part=statistics&id=${videoIds.join(',')}&key=${YOUTUBE_KEY}`
    );
    const statsData = await statsRes.json();
    const videoStats = statsData.items || [];

    // Calculate average views
    const viewCounts = videoStats.map(v => parseInt(v.statistics?.viewCount || 0));
    const avgViews = Math.round(viewCounts.reduce((a, b) => a + b, 0) / viewCounts.length);

    if (avgViews === 0) continue;

    // Find outliers
    for (const video of videoStats) {
      const views = parseInt(video.statistics?.viewCount || 0);
      if (views < avgViews * OUTLIER_THRESHOLD) continue;

      const videoId = video.id;
      const meta = videoMeta[videoId] || {};
      const outlierScore = (views / avgViews).toFixed(1);

      // Check Airtable for duplicate
      const dupRes = await fetch(
        `${AIRTABLE_BASE}/Outlier%20Videos?filterByFormula=${encodeURIComponent(`{Video ID}="${videoId}"`)}`,
        { headers: AT_HEADERS }
      );
      const dupData = await dupRes.json();
      if (dupData.records && dupData.records.length > 0) {
        results.push({ videoId, channelName, status: 'skip', reason: 'Already in Airtable' });
        continue;
      }

      // Get transcript from Supadata
      let transcript = '';
      try {
        const tRes = await fetch(
          `https://api.supadata.ai/v1/youtube/transcript?url=${encodeURIComponent(`https://www.youtube.com/watch?v=${videoId}`)}&text=true`,
          { headers: { 'x-api-key': SUPADATA_KEY } }
        );
        const tData = await tRes.json();
        transcript = tData.content || tData.text || tData.transcript || '';
      } catch (e) {
        transcript = '[Transcript unavailable — video may not have captions]';
      }

      // Rewrite with Claude
      let rewrittenScript = '';
      try {
        const claudeRes = await fetch('https://api.anthropic.com/v1/messages', {
          method: 'POST',
          headers: {
            'x-api-key': ANTHROPIC_KEY,
            'anthropic-version': '2023-06-01',
            'content-type': 'application/json'
          },
          body: JSON.stringify({
            model: 'claude-haiku-4-5-20251001',
            max_tokens: 4096,
            messages: [{
              role: 'user',
              content: BRAND_VOICE_PROMPT + (transcript.substring(0, 8000) || '[No transcript available — write a script based on the video title: ' + meta.title + ']')
            }]
          })
        });
        const claudeData = await claudeRes.json();
        rewrittenScript = claudeData.content?.[0]?.text || '[Script generation failed]';
      } catch (e) {
        rewrittenScript = `[Script generation failed: ${e.message}]`;
      }

      // Save to Airtable
      const createBody = {
        records: [{
          fields: {
            'Video Title': meta.title || 'Unknown Title',
            'Video ID': videoId,
            'Channel': [channelRecordId],
            'Views': views,
            'Channel Avg Views': avgViews,
            'Thumbnail': meta.thumbnail,
            'Transcript': transcript.substring(0, 100000),
            'Rewritten Script': rewrittenScript.substring(0, 100000),
            'Status': 'New',
            'Date Discovered': new Date().toISOString().split('T')[0]
          }
        }]
      };

      const createRes = await fetch(`${AIRTABLE_BASE}/Outlier%20Videos`, {
        method: 'POST',
        headers: AT_HEADERS,
        body: JSON.stringify(createBody)
      });
      const createData = await createRes.json();

      results.push({
        videoId,
        videoTitle: meta.title,
        channelName,
        views,
        avgViews,
        outlierScore: outlierScore + 'x',
        airtableId: createData.records?.[0]?.id || 'unknown',
        status: 'saved'
      });
    }

    // Update Last Scanned on the channel record
    await fetch(`${AIRTABLE_BASE}/Channels/${channelRecordId}`, {
      method: 'PATCH',
      headers: AT_HEADERS,
      body: JSON.stringify({
        fields: { 'Last Scanned': new Date().toISOString().split('T')[0] }
      })
    });

  } catch (e) {
    results.push({ channelName, status: 'error', error: e.message });
  }
}

// ---- Summary ----
const saved = results.filter(r => r.status === 'saved').length;
const skipped = results.filter(r => r.status === 'skip').length;
const errors = results.filter(r => r.status === 'error').length;

return [{
  json: {
    status: 'complete',
    run_date: new Date().toISOString(),
    channels_scanned: channels.length,
    outliers_saved: saved,
    skipped_duplicates: skipped,
    errors: errors,
    details: results
  }
}];
